    // Sort edges by time to process them in increasing order
    sort.Slice(edges, func(i, j int) bool {
        return edges[i][2] < edges[j][2]
    })

    // Union-Find data structure to track connected components
    parent := make([]int64, n)
    rank := make([]int64, n)

    for i := 0; i < n; i++ {
        parent[i] = int64(i)
        rank[i] = 0
