        if parent[u] != u {
            parent[u] = find(parent[u])
        }
        return parent[u]
    }

    // Union function with union by rank
    union := func(u, v int64) bool {
        rootU := find(u)
        rootV := find(v)
        if rootU == rootV {
            return false
        }
        if rank[rootU] < rank[rootV] {
            parent[rootU] = rootV
        } else {
            parent[rootV] = rootU
            if rank[rootU] == rank[rootV] {
                rank[rootU]++
            }
        }
        return true
    }

    // Initialize component count
    componentCount := n
    result := 0

    for _, edge := range edges {
        u, v, time := edge[0], edge[1], edge[2]
        if union(u, v) {
            componentCount--
            if componentCount == k {
                result = time
                break
            }
        }
    }

    return int64(result)
}
